INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4ba032d2-8a5f-4358-be69-b4b5055404e3',
  '00000000-0000-0000-0000-000000000001',
  $escape$Polars Data Cleaning — Nulls, Outliers, Types, and Dedup in One Pipeline$escape$,
  $escape$Polars expressions let you chain an entire cleaning pipeline without intermediate DataFrames. For nulls, `fill_null` with a strategy like `forward` or `mean` keeps things lazy-friendly, but `drop_nulls` on specific columns is often cleaner than blanket removal. Outlier detection fits naturally into `filter` — compute z-scores with `(col - col.mean()) / col.std()` and threshold inline. Type coercion via `cast` is strict by default; use `strict=False` to coerce failures to null rather than panicking, then handle those nulls downstream. Deduplication with `unique` accepts a `keep` parameter (`first`, `last`, `none`) and a `subset` of columns — critical when your key isn't the full row. The real power: all of this composes in a single `lazy()` pipeline. The query optimizer reorders and fuses operations, so writing readable step-by-step transforms costs you nothing at execution time. Always prefer `lazy` mode for cleaning — eager frames skip the optimizer entirely.$escape$,
  $escape$import polars as pl

df = pl.scan_csv("raw_data.csv")

cleaned = (
    df
    .with_columns(
        pl.col("price").cast(pl.Float64, strict=False),
        pl.col("category").fill_null("unknown"),
    )
    .filter(
        ((pl.col("price") - pl.col("price").mean()) / pl.col("price").std()).abs() < 3
    )
    .unique(subset=["product_id", "timestamp"], keep="last")
    .drop_nulls(subset=["price"])
    .collect()
)$escape$,
  $escape$python$escape$,
