INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '33619a06-41bd-4c00-960b-ea398c91cef7',
  '00000000-0000-0000-0000-000000000001',
  $escape$Polars Feature Engineering — Categoricals, Scaling, and Binning Without Leaving Lazy Mode$escape$,
  $escape$Polars expressions make feature engineering composable and fast — no need to drop into pandas or sklearn. For one-hot encoding, cast to `Categorical` then use `to_dummies()` on the DataFrame. For target/label encoding, use a `group_by` aggregation joined back. Numerical scaling is a single expression: `(col - col.mean()) / col.std()` for z-score, or `(col - col.min()) / (col.max() - col.min())` for min-max. Binning uses `cut()` or `.over()` with `qcut()` for quantile bins. Interaction features are trivial — multiply or concatenate columns inline with `with_columns`. The key advantage: all of these work in lazy mode, so Polars optimizes the entire pipeline before execution. Chain them in a single `with_columns` block to avoid redundant passes. Use `Enum` dtype over `Categorical` when your categories are fixed and known ahead of time — it's stricter and catches invalid values at cast time rather than silently adding them.$escape$,
  $escape$import polars as pl

df = pl.LazyFrame({"city": ["NYC","SF","NYC","LA"], "price": [100,250,150,90], "sqft": [500,800,600,400]})

result = df.with_columns(
    # min-max scaling
    ((pl.col("price") - pl.col("price").min()) / (pl.col("price").max() - pl.col("price").min())).alias("price_scaled"),
    # quantile binning
    pl.col("sqft").qcut(3, labels=["small","mid","large"]).alias("size_bin"),
    # interaction feature
    (pl.col("price") / pl.col("sqft")).alias("price_per_sqft"),
    # label encoding via rank
    pl.col("city").cast(pl.Categorical).to_physical().alias("city_encoded"),
).collect()

print(result)$escape$,
  $escape$python$escape$,
